// Generate Pro Forma Forecast - UPDATED COST STRUCTURE
const inputData = $input.all();

console.log("Input data items:", inputData.length);

// Find QB data - same logic as before
let qbData = null;
for (let i = 0; i < inputData.length; i++) {
  const item = inputData[i];
  if (!item || !item.json) continue;

  const data = item.json;

  if (data.qbData && data.qbData.qbData && data.qbData.qbData.monthlyRevenue) {
    qbData = { json: data.qbData.qbData };
    console.log("Found double-nested QB data");
    break;
  }

  if (data.qbData && data.qbData.monthlyRevenue) {
    qbData = { json: data.qbData };
    console.log("Found nested QB data");
    break;
  }
}

// Find business data
let businessData = inputData.find(item => 
  item.json.businessAssumptions || 
  item.json.operatorName ||
  item.json.fleetUtilization
);

// Extract actual financial data
let actualRevenue = {};
let totalActual = 0;
let trailing12M = 0;
let monthsOfData = 0;

if (qbData && qbData.json && qbData.json.monthlyRevenue) {
  const data = qbData.json;
  actualRevenue = data.monthlyRevenue;
  totalActual = data.totalRevenue || 0;
  trailing12M = data.trailing12M || data.trailing6M || data.trailing2M || 0;
  monthsOfData = data.totalMonths || Object.keys(actualRevenue).length;

  console.log("✅ Found QB data:", {
    actualRevenue,
    totalActual,
    trailing12M,
    monthsOfData
  });
}

// Business assumptions - UPDATED COST STRUCTURE
const assumptions = businessData ? businessData.json.businessAssumptions || businessData.json : {};
const baseGrowthRate = 0.05; // 5% annual growth

// NEW COST STRUCTURE PER YOUR REQUIREMENTS
const materialsPercent = 0.23; // 23% materials
const directLaborPercent = 0.18; // 18% direct labor
const totalCogsPercent = materialsPercent + directLaborPercent; // 41% total COGS
const opexPercent = 0.40; // 40% OpEx
const targetNetMargin = 0.12; // 12% net profit target (middle of 10-14% range)

console.log("✅ Using cost structure: Materials 23%, Labor 18%, OpEx 40%, Target Net 12%");

// FIXED BASELINE CALCULATION - Don't use partial months!
let monthlyBaseline = 0;
const months = Object.keys(actualRevenue).sort();

if (months.length > 0) {
  // Exclude the current month if it's incomplete (very low revenue)
  const fullMonths = [];
  const currentMonth = new Date().toISOString().slice(0, 7);

  months.forEach(month => {
    const revenue = actualRevenue[month];
    // Skip current month if it's very low (indicates partial month)
    if (month === currentMonth && revenue < 50000) {
      console.log(`Skipping partial month ${month} with revenue ${revenue}`);
      return;
    }
    fullMonths.push(revenue);
  });

  if (fullMonths.length > 0) {
    // Use average of full months
    monthlyBaseline = fullMonths.reduce((sum, rev) => sum + rev, 0) / fullMonths.length;
    console.log(`✅ Calculated baseline from ${fullMonths.length} full months:`, monthlyBaseline);
  } else {
    // Fallback to total average
    monthlyBaseline = totalActual / months.length;
    console.log("⚠️ Using total average as baseline:", monthlyBaseline);
  }
} else {
  // Ultimate fallback
  monthlyBaseline = 150000;
  console.log("❌ No actual data, using default baseline:", monthlyBaseline);
}

// Generate monthly data for dashboard
const monthlyData = [];
const currentDate = new Date();

// Add actual historical data first - EXCLUDE CURRENT PARTIAL MONTH
const actualMonths = Object.keys(actualRevenue).sort();
const currentMonthKey = new Date().toISOString().slice(0, 7);

actualMonths.forEach(monthKey => {
  // Skip current month if it looks partial (low revenue)
  if (monthKey === currentMonthKey && actualRevenue[monthKey] < 50000) {
    console.log(`Excluding partial month ${monthKey} from chart`);
    return;
  }

  const date = new Date(monthKey + '-01');
  const monthName = date.toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
  const revenue = actualRevenue[monthKey];

  // Calculate costs with new structure
  const materials = Math.round(revenue * materialsPercent);
  const directLabor = Math.round(revenue * directLaborPercent);
  const totalCogs = materials + directLabor;
  const grossProfit = revenue - totalCogs;
  const opex = Math.round(revenue * opexPercent);
  const ebitda = grossProfit - opex;
  const netProfit = ebitda; // Simplified - no other expenses for now

  monthlyData.push({
    dateLabel: monthName,
    month: monthKey,
    monthName: monthName,
    period: 'Actual',
    scenario: 'Base Case',
    revenue: revenue,
    materials: materials,
    directLabor: directLabor,
    totalCogs: totalCogs,
    grossProfit: grossProfit,
    opex: opex,
    ebitda: ebitda,
    netProfit: netProfit,
    operatingCF: Math.round(netProfit * 1.1), // Approx cash flow
    // Maintain backward compatibility
    cogs: totalCogs
  });
});

// Generate forecast data for each scenario - START FROM NEXT FULL MONTH
const scenarios = [
  { name: 'Base Case', multiplier: 1.0 },
  { name: 'Aggressive', multiplier: 1.25 },
  { name: 'Conservative', multiplier: 0.8 }
];

scenarios.forEach(scenario => {
  // Start forecasting from next month (skip current partial month)
  for (let i = 1; i <= 36; i++) {
    const forecastDate = new Date(currentDate);
    forecastDate.setMonth(currentDate.getMonth() + i);

    const monthKey = forecastDate.toISOString().slice(0, 7);
    const monthName = forecastDate.toLocaleDateString('en-US', { month: 'short', year: 'numeric' });

    // Better growth calculation
    const growthMultiplier = Math.pow(1 + baseGrowthRate, i / 12); // Annual compounding

    // Seasonal pattern for gutter business
    const seasonalMultiplier = 1 + 0.15 * Math.sin((forecastDate.getMonth() + 1 - 2) * Math.PI / 6);

    // Calculate forecast revenue
    const baseRevenue = monthlyBaseline * growthMultiplier * seasonalMultiplier * scenario.multiplier;
    const revenue = Math.round(baseRevenue);

    // Calculate costs with new detailed structure
    const materials = Math.round(revenue * materialsPercent);
    const directLabor = Math.round(revenue * directLaborPercent);
    const totalCogs = materials + directLabor;
    const grossProfit = revenue - totalCogs;
    const opex = Math.round(revenue * opexPercent);
    const ebitda = grossProfit - opex;
    const netProfit = ebitda;

    monthlyData.push({
      dateLabel: monthName,
      month: monthKey,
      monthName: monthName,
      period: 'Forecast',
      scenario: scenario.name,
      revenue: revenue,
      materials: materials,
      directLabor: directLabor,
      totalCogs: totalCogs,
      grossProfit: grossProfit,
      opex: opex,
      ebitda: ebitda,
      netProfit: netProfit,
      operatingCF: Math.round(netProfit * 1.1),
      // Maintain backward compatibility
      cogs: totalCogs
    });
  }
});

// Create period summaries
const periodSummaries = [];

scenarios.forEach(scenario => {
  const scenarioForecast = monthlyData.filter(m => m.period === 'Forecast' && m.scenario === scenario.name);

  // Trailing 12M (actual data)
  periodSummaries.push({
    period: 'Trailing 12M',
    scenario: scenario.name,
    revenue: trailing12M,
    materials: Math.round(trailing12M * materialsPercent),
    directLabor: Math.round(trailing12M * directLaborPercent),
    totalCogs: Math.round(trailing12M * totalCogsPercent),
    grossProfit: Math.round(trailing12M * (1 - totalCogsPercent)),
    opex: Math.round(trailing12M * opexPercent),
    netProfit: Math.round(trailing12M * (1 - totalCogsPercent - opexPercent)),
    operatingCF: Math.round(trailing12M * (1 - totalCogsPercent - opexPercent) * 1.1)
  });

  // Year 1 forecast
  const year1Data = scenarioForecast.slice(0, 12);
  const year1Revenue = year1Data.reduce((sum, m) => sum + m.revenue, 0);
  periodSummaries.push({
    period: 'Year 1',
    scenario: scenario.name,
    revenue: year1Revenue,
    materials: year1Data.reduce((sum, m) => sum + m.materials, 0),
    directLabor: year1Data.reduce((sum, m) => sum + m.directLabor, 0),
    totalCogs: year1Data.reduce((sum, m) => sum + m.totalCogs, 0),
    grossProfit: year1Data.reduce((sum, m) => sum + m.grossProfit, 0),
    opex: year1Data.reduce((sum, m) => sum + m.opex, 0),
    netProfit: year1Data.reduce((sum, m) => sum + m.netProfit, 0),
    operatingCF: year1Data.reduce((sum, m) => sum + m.operatingCF, 0)
  });

  // Year 2 forecast
  const year2Data = scenarioForecast.slice(12, 24);
  const year2Revenue = year2Data.reduce((sum, m) => sum + m.revenue, 0);
  periodSummaries.push({
    period: 'Year 2',
    scenario: scenario.name,
    revenue: year2Revenue,
    materials: year2Data.reduce((sum, m) => sum + m.materials, 0),
    directLabor: year2Data.reduce((sum, m) => sum + m.directLabor, 0),
    totalCogs: year2Data.reduce((sum, m) => sum + m.totalCogs, 0),
    grossProfit: year2Data.reduce((sum, m) => sum + m.grossProfit, 0),
    opex: year2Data.reduce((sum, m) => sum + m.opex, 0),
    netProfit: year2Data.reduce((sum, m) => sum + m.netProfit, 0),
    operatingCF: year2Data.reduce((sum, m) => sum + m.operatingCF, 0)
  });

  // Year 3 forecast
  const year3Data = scenarioForecast.slice(24, 36);
  const year3Revenue = year3Data.reduce((sum, m) => sum + m.revenue, 0);
  periodSummaries.push({
    period: 'Year 3',
    scenario: scenario.name,
    revenue: year3Revenue,
    materials: year3Data.reduce((sum, m) => sum + m.materials, 0),
    directLabor: year3Data.reduce((sum, m) => sum + m.directLabor, 0),
    totalCogs: year3Data.reduce((sum, m) => sum + m.totalCogs, 0),
    grossProfit: year3Data.reduce((sum, m) => sum + m.grossProfit, 0),
    opex: year3Data.reduce((sum, m) => sum + m.opex, 0),
    netProfit: year3Data.reduce((sum, m) => sum + m.netProfit, 0),
    operatingCF: year3Data.reduce((sum, m) => sum + m.operatingCF, 0)
  });
});

// Build final forecast object
const forecast = {
  monthlyData: monthlyData,
  periodSummaries: periodSummaries,
  businessAssumptions: assumptions,
  generatedAt: new Date().toISOString(),
  dataSource: "automated_forecast_updated_costs",

  // Cost structure documentation
  costStructure: {
    materials: `${materialsPercent * 100}%`,
    directLabor: `${directLaborPercent * 100}%`,
    totalCogs: `${totalCogsPercent * 100}%`,
    opex: `${opexPercent * 100}%`,
    targetNetMargin: `${targetNetMargin * 100}%`
  },

  debugInfo: {
    baselineUsed: Math.round(monthlyBaseline),
    excludedPartialMonth: currentMonthKey,
    actualMonthsIncluded: monthlyData.filter(m => m.period === 'Actual').length,
    forecastRecords: monthlyData.filter(m => m.period === 'Forecast').length
  }
};

console.log("✅ Generated forecast with updated cost structure");
console.log("✅ Materials: 23%, Direct Labor: 18%, OpEx: 40%");
console.log("✅ Total monthly records:", monthlyData.length);

return [{ json: forecast }];

