// Helper function to sum data by period and scenario
function summarizeByPeriod(data, metric, scenario) {
  const scenarioData = data.filter(row => row.scenario === scenario);

  const trailing12M = scenarioData
    .filter(row => row.month >= 1 && row.month <= 12)
    .reduce((sum, row) => sum + (row[metric] || 0), 0);

  const year1 = scenarioData
    .filter(row => row.month >= 13 && row.month <= 24)
    .reduce((sum, row) => sum + (row[metric] || 0), 0);

  const year2 = scenarioData
    .filter(row => row.month >= 25 && row.month <= 36)
    .reduce((sum, row) => sum + (row[metric] || 0), 0);

  const year3 = scenarioData
    .filter(row => row.month >= 37 && row.month <= 48)
    .reduce((sum, row) => sum + (row[metric] || 0), 0);

  return { trailing12M, year1, year2, year3 };
}

// Helper function to calculate growth rates
function calculateGrowth(baseline, current) {
  if (baseline === 0) return '0%';
  const growth = ((current - baseline) / baseline * 100).toFixed(1);
  return `${growth}%`;
}

// Define scenarios and metrics
const scenarios = ['Base Case', 'Aggressive', 'Conservative'];
const metrics = [
  { key: 'revenue', label: 'Revenue' },
  { key: 'cogs', label: 'Cost of Goods Sold' },
  { key: 'grossProfit', label: 'Gross Profit' },
  { key: 'operatingExpense', label: 'Operating Expenses' },
  { key: 'ebitda', label: 'EBITDA' },
  { key: 'netProfit', label: 'Net Profit' },
  { key: 'operatingCF', label: 'Operating Cash Flow' },
