let csvContent = 'Metric,Scenario,Trailing 12M,Year 1,Year 2,Year 3,Growth Y1,Growth Y2,Growth Y3\n';

// Process each metric for each scenario
metrics.forEach(metric => {
  scenarios.forEach(scenario => {
    const summary = summarizeByPeriod(monthlyData, metric.key, scenario);

    // Calculate growth rates
    const growthY1 = calculateGrowth(summary.trailing12M, summary.year1);
    const growthY2 = calculateGrowth(summary.year1, summary.year2);
    const growthY3 = calculateGrowth(summary.year2, summary.year3);

    // Format numbers
    const trailing12M = Math.round(summary.trailing12M);
    const year1 = Math.round(summary.year1);
    const year2 = Math.round(summary.year2);
    const year3 = Math.round(summary.year3);

    // Add row to CSV
    csvContent += [
      metric.label,
      scenario,
      trailing12M,
      year1,
      year2,
      year3,
      growthY1,
      growthY2,
      growthY3
    ].join(',') + '\n';
  });
});

// Add financial ratios
csvContent += '\n// FINANCIAL RATIOS\n';
csvContent += 'Ratio,Scenario,Trailing 12M,Year 1,Year 2,Year 3,Change Y1,Change Y2,Change Y3\n';

scenarios.forEach(scenario => {
  const revenueSummary = summarizeByPeriod(monthlyData, 'revenue', scenario);
  const grossProfitSummary = summarizeByPeriod(monthlyData, 'grossProfit', scenario);
  const netProfitSummary = summarizeByPeriod(monthlyData, 'netProfit', scenario);

  // Calculate margins
  const grossMarginT12 = revenueSummary.trailing12M > 0 ? 
    ((grossProfitSummary.trailing12M / revenueSummary.trailing12M) * 100).toFixed(1) : '0.0';
  const grossMarginY1 = revenueSummary.year1 > 0 ? 
